        /// <inheritdoc/>
        public override bool Equals(object obj)
        {
            if (obj is null) return false;
            if (ReferenceEquals(this, obj)) return true;

            return obj is AchProductTransaction other &&
                (this.ProcessorVersion == null && other.ProcessorVersion == null ||
                 this.ProcessorVersion?.Equals(other.ProcessorVersion) == true) &&
                (this.IndustryType == null && other.IndustryType == null ||
